import{_ as o,o as a,c as r,a3 as e}from"./chunks/framework.DACwFHq9.js";const g=JSON.parse('{"title":"JSON 格式化","description":"","frontmatter":{},"headers":[],"relativePath":"user-guide/tools/json-formatter.md","filePath":"user-guide/tools/json-formatter.md","lastUpdated":1778221347000}'),l={name:"user-guide/tools/json-formatter.md"};function s(n,t,i,d,h,c){return a(),r("div",null,[...t[0]||(t[0]=[e('<h1 id="json-格式化" tabindex="-1">JSON 格式化 <a class="header-anchor" href="#json-格式化" aria-label="Permalink to &quot;JSON 格式化&quot;">​</a></h1><h2 id="概述" tabindex="-1">概述 <a class="header-anchor" href="#概述" aria-label="Permalink to &quot;概述&quot;">​</a></h2><p>JSON 格式化工具是一个专注的 JSON 数据格式化和校验工具。当你面对一大段压缩成单行的 JSON 时，它能一键展开成结构清晰的层级树；当你需要快速验证一段 JSON 是否合法时，它会实时给出反馈。它最大的特色是<strong>可控展开层级</strong>——你可以精确控制折叠深度，让复杂数据结构一目了然，而不是无差别地全部展开。</p><h3 id="核心功能" tabindex="-1">核心功能 <a class="header-anchor" href="#核心功能" aria-label="Permalink to &quot;核心功能&quot;">​</a></h3><ul><li><strong>实时格式化和校验</strong>：输入即格式化，同时自动校验 JSON 合法性，错误位置一目了然</li><li><strong>可控展开层级</strong>：通过滑块或数字输入精确控制展开深度（1–10 级），深层嵌套自动折叠为紧凑格式</li><li><strong>剪贴板智能监听</strong>：开启后自动检测剪贴板中的 JSON 内容，一键填入</li><li><strong>文件拖拽导入</strong>：支持拖拽 <code>.json</code> 或 <code>.txt</code> 文件到输入面板，自动读取内容</li><li><strong>一键复制与发送</strong>：格式化结果一键复制到剪贴板，或直接发送到 AI 聊天会话</li></ul><h2 id="快速上手" tabindex="-1">快速上手 <a class="header-anchor" href="#快速上手" aria-label="Permalink to &quot;快速上手&quot;">​</a></h2><h3 id="首次使用-4-步走" tabindex="-1">首次使用 4 步走 <a class="header-anchor" href="#首次使用-4-步走" aria-label="Permalink to &quot;首次使用 4 步走&quot;">​</a></h3><p><strong>第一步：打开工具</strong></p><p>在左侧工具列表中找到 <strong>JSON 格式化</strong>，点击进入。你会看到一个&quot;左输入 + 右输出&quot;的双面板界面，顶部是工具栏。</p><blockquote><p>TODO: 截图 - 工具整体界面，标注输入面板、输出面板和工具栏</p></blockquote><p><strong>第二步：输入 JSON</strong></p><p>有三种方式把你的 JSON 弄进去：</p><ul><li><strong>直接输入</strong>：在左侧输入面板中直接键入或粘贴 JSON 文本</li><li><strong>从剪贴板粘贴</strong>：点击工具栏的 <strong>粘贴</strong> 按钮，自动读取剪贴板内容</li><li><strong>拖拽文件</strong>：将 <code>.json</code> 或 <code>.txt</code> 文件拖放到输入面板区域</li></ul><p>内容输入后，工具会<strong>自动</strong>开始格式化和校验，输出面板会实时更新。</p><blockquote><p>TODO: 截图 - 输入面板粘贴/输入 JSON，输出面板展示格式化结果</p></blockquote><p><strong>第三步：调整展开层级</strong></p><p>输入面板上方的工具栏中间有一个<strong>展开层级</strong>滑块（默认 3 级），拖动滑块或直接在右侧数字框中输入数值来控制 JSON 的展开深度：</p><ul><li><strong>值较小（如 1）</strong>：只展开最外层，深层内容紧凑显示，适合快速浏览整体结构</li><li><strong>值较大（如 5–10）</strong>：展开更多层级，适合查看深层细节</li></ul><blockquote><p>TODO: 截图 - 标注展开层级滑块和数字输入框，展示不同层级下的格式化效果对比</p></blockquote><p><strong>第四步：使用结果</strong></p><p>右侧输出面板中的格式化结果，你可以：</p><ul><li><strong>复制</strong>：点击工具栏的 <strong>复制</strong> 按钮，一键复制到剪贴板</li><li><strong>发送到聊天</strong>：点击 <strong>发送到聊天</strong>，结果直接进入 AI 聊天会话</li><li><strong>清空重来</strong>：点击 <strong>清空</strong> 按钮重置输入和输出</li></ul><blockquote><p>TODO: 截图 - 标注工具栏的复制、发送到聊天、清空按钮</p></blockquote><h2 id="功能详解" tabindex="-1">功能详解 <a class="header-anchor" href="#功能详解" aria-label="Permalink to &quot;功能详解&quot;">​</a></h2><h3 id="工具栏" tabindex="-1">工具栏 <a class="header-anchor" href="#工具栏" aria-label="Permalink to &quot;工具栏&quot;">​</a></h3><p>工具栏固定在面板顶部，分为左、中、右三个区域。</p><h4 id="左侧操作区" tabindex="-1">左侧操作区 <a class="header-anchor" href="#左侧操作区" aria-label="Permalink to &quot;左侧操作区&quot;">​</a></h4><table tabindex="0"><thead><tr><th>操作</th><th>说明</th></tr></thead><tbody><tr><td><strong>粘贴</strong></td><td>从系统剪贴板读取内容并填入输入面板，自动触发格式化</td></tr><tr><td><strong>复制</strong></td><td>将输出面板中的格式化结果复制到系统剪贴板</td></tr><tr><td><strong>发送到聊天</strong></td><td>将格式化后的 JSON 发送到 AI 聊天会话，方便后续基于它继续对话</td></tr><tr><td><strong>监听关 / 监听中</strong></td><td>切换剪贴板智能监听功能（见下方详细介绍）</td></tr></tbody></table><blockquote><p>TODO: 截图 - 工具栏左侧区域，标注四个操作按钮</p></blockquote><h4 id="中央展开层级控制" tabindex="-1">中央展开层级控制 <a class="header-anchor" href="#中央展开层级控制" aria-label="Permalink to &quot;中央展开层级控制&quot;">​</a></h4><p>通过 <strong>滑块</strong> 或 <strong>数字输入框</strong> 控制 JSON 的展开深度，范围 1–10。两者联动——拖动滑块时数字自动更新，输入数字时滑块同步移动。调整后输出面板会立即重新格式化。</p><ul><li><strong>1–2</strong>：适合超深层嵌套的 JSON，只看顶层的结构骨架</li><li><strong>3–4</strong>：默认范围，兼顾结构与细节的平衡</li><li><strong>5–10</strong>：深层展开，适合需要查看全部细节的场景</li></ul><blockquote><p>TODO: 截图 - 工具栏中央，同时标注滑块和数字输入框</p></blockquote><h4 id="右侧操作区" tabindex="-1">右侧操作区 <a class="header-anchor" href="#右侧操作区" aria-label="Permalink to &quot;右侧操作区&quot;">​</a></h4><table tabindex="0"><thead><tr><th>操作</th><th>说明</th></tr></thead><tbody><tr><td><strong>清空</strong></td><td>一键清空输入面板和输出面板的所有内容</td></tr></tbody></table><h3 id="输入面板-左栏" tabindex="-1">输入面板（左栏） <a class="header-anchor" href="#输入面板-左栏" aria-label="Permalink to &quot;输入面板（左栏）&quot;">​</a></h3><p>左侧的代码编辑器区域，使用 <code>RichCodeEditor</code> 组件，支持 JSON 语法高亮。你可以：</p><ul><li><strong>直接输入或粘贴</strong> JSON 文本</li><li><strong>拖拽文件</strong>到输入区域——文件拖入时会有蓝色虚线边框提示，松开后自动读取内容</li><li><strong>查看字符数</strong>：面板顶部的标题栏右侧会实时显示当前输入的字符数量</li></ul><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>支持拖拽的格式为 <code>.json</code> 和 <code>.txt</code> 文件。其他格式文件拖入会被拒绝并提示&quot;仅支持 JSON 或文本文件&quot;。</p></div><blockquote><p>TODO: 截图 - 拖拽文件到输入面板时的蓝色虚线边框提示效果</p></blockquote><h3 id="输出面板-右栏" tabindex="-1">输出面板（右栏） <a class="header-anchor" href="#输出面板-右栏" aria-label="Permalink to &quot;输出面板（右栏）&quot;">​</a></h3><p>右侧展示格式化后的 JSON 内容。输出面板是<strong>只读</strong>的，不可编辑。面板顶部的标题会根据当前状态动态变化：</p><ul><li><strong>格式化输出 - 有效 JSON</strong>：当输入为合法 JSON 时显示</li><li><strong>格式化输出 - 错误</strong>：当输入为非法 JSON 时显示（同时面板中会展示红色错误信息）</li></ul><blockquote><p>TODO: 截图 - 有效 JSON 时的输出面板，标注标题&quot;格式化输出 - 有效 JSON&quot;</p></blockquote><h4 id="错误提示" tabindex="-1">错误提示 <a class="header-anchor" href="#错误提示" aria-label="Permalink to &quot;错误提示&quot;">​</a></h4><p>当输入的 JSON 不合法（如缺少逗号、括号不匹配等）时，输出面板会显示红色错误提示框，包含具体的错误信息，帮助你快速定位问题：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>JSON 解析错误: Unexpected token &#39;...&#39; at position ...</span></span></code></pre></div><p>同时输出面板标题变为 <strong>格式化输出 - 错误</strong>。</p><blockquote><p>TODO: 截图 - 非法 JSON 时的错误提示框，标注红色边框的错误信息</p></blockquote><h3 id="分割线拖拽" tabindex="-1">分割线拖拽 <a class="header-anchor" href="#分割线拖拽" aria-label="Permalink to &quot;分割线拖拽&quot;">​</a></h3><p>输入面板和输出面板之间有一条垂直的分割线。你可以<strong>拖拽分割线</strong>左右移动，调整两个面板的宽度比例：</p><ul><li>将分割线拖向左侧：输入面板变窄，输出面板变宽</li><li>将分割线拖向右侧：输入面板变宽，输出面板变窄</li><li>每个面板的最小宽度为 100px</li></ul><blockquote><p>TODO: 截图 - 拖拽分割线调整面板宽度的动态效果</p></blockquote><p>在窄屏（宽度小于 768px）时，布局会自动切换为<strong>上下结构</strong>，分割线变为水平方向，可以上下拖拽调整高度。</p><h3 id="剪贴板智能监听" tabindex="-1">剪贴板智能监听 <a class="header-anchor" href="#剪贴板智能监听" aria-label="Permalink to &quot;剪贴板智能监听&quot;">​</a></h3><p>这是一个很有特色的功能——开启后，工具会在后台持续监听系统剪贴板。当检测到剪贴板内容为 JSON 格式时：</p><ul><li><strong>输入面板为空</strong>：自动填入内容并格式化，右下角提示&quot;已自动检测并粘贴 JSON 内容&quot;</li><li><strong>输入面板已有内容</strong>：在屏幕右下角弹出一个通知，点击通知即可替换为新的剪贴板内容</li></ul><p>点击工具栏的 <strong>监听关</strong> 按钮开启监听（按钮变为 <strong>监听中</strong> 并高亮为黄色），再次点击则关闭。</p><div class="tip custom-block"><p class="custom-block-title">使用场景</p><p>当你需要反复从不同地方（如浏览器、编辑器、API 文档）复制 JSON 过来检查时，开启剪贴板监听可以省去每次手动粘贴的步骤，非常高效。</p></div><blockquote><p>TODO: 截图 - 剪贴板监听开启时的通知弹窗</p></blockquote><h2 id="高级用法" tabindex="-1">高级用法 <a class="header-anchor" href="#高级用法" aria-label="Permalink to &quot;高级用法&quot;">​</a></h2><h3 id="与-ai-聊天联动" tabindex="-1">与 AI 聊天联动 <a class="header-anchor" href="#与-ai-聊天联动" aria-label="Permalink to &quot;与 AI 聊天联动&quot;">​</a></h3><p>格式化后的 JSON 可以通过 <strong>发送到聊天</strong> 按钮直接传入 AI 聊天会话。例如：</p><ol><li>从 API 文档复制一段 JSON 到工具中格式化</li><li>确认结构无误后，点击 <strong>发送到聊天</strong></li><li>在聊天中追问 AI：&quot;帮我分析这个 JSON 的结构&quot; 或 &quot;基于这个 JSON 生成 TypeScript 类型定义&quot;</li></ol><h3 id="利用展开层级快速定位数据结构" tabindex="-1">利用展开层级快速定位数据结构 <a class="header-anchor" href="#利用展开层级快速定位数据结构" aria-label="Permalink to &quot;利用展开层级快速定位数据结构&quot;">​</a></h3><p>当处理深度嵌套的 JSON（如复杂的 API 响应）时，可以利用展开层级来快速理解结构：</p><ol><li>先将展开层级设为 <strong>1</strong>，只看最顶层有哪些字段</li><li>逐步增加到 <strong>2</strong>、<strong>3</strong>，逐层深入查看子结构</li><li>找到感兴趣的字段后，增加到更大的值查看其完整内容</li></ol><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><h3 id="q-为什么我输入-json-后没有看到格式化效果" tabindex="-1">Q：为什么我输入 JSON 后没有看到格式化效果？ <a class="header-anchor" href="#q-为什么我输入-json-后没有看到格式化效果" aria-label="Permalink to &quot;Q：为什么我输入 JSON 后没有看到格式化效果？&quot;">​</a></h3><p>检查一下你输入的 JSON 是否合法。如果 JSON 格式错误，输出面板会显示红色错误提示框，里面会写清楚具体的错误原因。常见错误包括：</p><ul><li>缺少逗号</li><li>多余的逗号（如数组或对象的最后一个元素后面有逗号）</li><li>键名没有用双引号包裹</li><li>括号不匹配</li></ul><h3 id="q-展开层级调到最大-10-还是显示不全怎么办" tabindex="-1">Q：展开层级调到最大（10）还是显示不全怎么办？ <a class="header-anchor" href="#q-展开层级调到最大-10-还是显示不全怎么办" aria-label="Permalink to &quot;Q：展开层级调到最大（10）还是显示不全怎么办？&quot;">​</a></h3><p>展开层级为 10 时，工具会展开到第 10 层嵌套。如果你的 JSON 嵌套深度超过 10 层，更深的部分会自动以紧凑格式显示（即 JSON 压缩成单行）。这通常是合理的——查看超过 10 层嵌套的数据，反而会让信息密度过高难以阅读。</p><p>如果需要查看更底层的内容，可以将目标部分的 JSON 片段单独复制出来格式化。</p><h3 id="q-拖拽文件时没有反应" tabindex="-1">Q：拖拽文件时没有反应？ <a class="header-anchor" href="#q-拖拽文件时没有反应" aria-label="Permalink to &quot;Q：拖拽文件时没有反应？&quot;">​</a></h3><p>请确认你拖拽的是 <code>.json</code> 或 <code>.txt</code> 文件，并且是拖放到<strong>输入面板</strong>区域（左侧）。拖拽时输入面板会显示蓝色虚线边框作为视觉反馈。如果拖放到输出面板或其他区域则不会有反应。</p><h3 id="q-剪贴板监听会影响正常复制粘贴吗" tabindex="-1">Q：剪贴板监听会影响正常复制粘贴吗？ <a class="header-anchor" href="#q-剪贴板监听会影响正常复制粘贴吗" aria-label="Permalink to &quot;Q：剪贴板监听会影响正常复制粘贴吗？&quot;">​</a></h3><p>不会。剪贴板监听只在 JSON 格式化工具处于打开状态且已手动开启监听时工作。它会智能过滤掉你自己在工具内部的复制操作（不会复制了格式化结果又触发一次替换）。开启监听后，只有当剪贴板中出现的是 JSON 格式的内容时才会触发提示或自动填充，不影响你对其他文本的复制粘贴操作。</p><h3 id="q-支持-json-以外的格式吗" tabindex="-1">Q：支持 JSON 以外的格式吗？ <a class="header-anchor" href="#q-支持-json-以外的格式吗" aria-label="Permalink to &quot;Q：支持 JSON 以外的格式吗？&quot;">​</a></h3><p>目前工具专注于 JSON 格式的格式化和校验。支持通过拖拽 <code>.txt</code> 文件来输入文本内容，但这些文本内容仍然需要是合法的 JSON 格式才能被正确格式化。如果你需要处理 YAML 或其他数据格式，可以查看 <a href="/user-guide/tools/data-filter">数据筛选工具</a> 等其他工具。</p>',80)])])}const p=o(l,[["render",s]]);export{g as __pageData,p as default};
